            .map(|i| (i as f64) * 0.3 + 0.1 * (i as f64).powi(2))
            .collect();
        let y_values: Vec<f64> = x1_values
            .iter()
            .zip(x2_values.iter())
            .map(|(&x1, &x2)| 2.0 + 1.5 * x1 + 0.8 * x2 + 0.1 * x1 * x2.sin())
            .collect();

        // Design matrix: [1, x1, x2] - now without perfect multicollinearity
        let mut x_data = Vec::with_capacity(n_obs * 3);
        for i in 0..n_obs {
            x_data.push(1.0); // intercept
            x_data.push(x1_values[i]); // x1
            x_data.push(x2_values[i]); // x2
        }

        println!("=== Multiple Regression Debug ===");
        println!("x1: {:?}", x1_values);
        println!("x2: {:?}", x2_values);
        println!("x2 is not perfectly correlated with x1");

        let x_mat = Mat::from_fn(n_obs, 3, |i, j| x_data[i * 3 + j]);
        let _y_mat = Mat::from_fn(n_obs, 1, |i, _| y_values[i]);

        println!("Design matrix X (first 3 rows):");
        for i in 0..3 {
            println!(
                "  [{}, {}, {}]",
                x_mat[(i, 0)],
                x_mat[(i, 1)],
                x_mat[(i, 2)]
            );
        }

        let qr = x_mat.col_piv_qr();
        let r_matrix = qr.R();

        println!("R matrix diagonal:");
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            println!("  R[{},{}] = {}", i, i, r_matrix[(i, i)]);
        }

        // Detect rank
        let tolerance = 1e-12;
        let mut rank = 0;
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            if r_matrix[(i, i)].abs() > tolerance {
                rank += 1;
            }
        }
        println!("Detected rank: {} (should be 3 for full rank)", rank);

        let fit = Lm::fit(&x_data, &y_values, n_obs, 3).unwrap();
